#include<bits/stdc++.h>
using namespace std;
const int MAXN = 2e4 + 10;
vector<pair<int, int> >edge[MAXN];
int dis[MAXN],vis[MAXN];
int n, m, s, t;
int mini = MAXN;
void dij(){ 
	priority_queue<pair<int,int>, vector<pair<int,int> >, greater<pair<int,int> > >q;
	q.push({dis[s],s});
	while(q.size()){
		int u = q.top().second;
		q.pop();
		for(int i = 0; i < edge[u].size(); i++){
			int v = edge[u][i].first;
			int d = edge[u][i].second;
			int k = max(dis[u], d);
			if(k < dis[edge[u][i].first]){
				dis[edge[u][i].first] = k;
				q.push({dis[edge[u][i].first], edge[u][i].first});
			}

		}
	}
}
int main()
{
	for(int i = 0 ; i < MAXN; i++) dis[i] = MAXN;
	cin >> n >> m >> s >> t;
	for(int i = 0; i < m; i++){
		int u, v, w;
		cin >> u >> v >> w;
		edge[u].push_back({v, w});
		edge[v].push_back({u, w});
	}
	dis[s] = 0;
	dij();
	cout << dis[t];
	return 0;
}
